pragma cashscript ~0.13.0;

contract Manager(bytes inflowToken, bytes outflowToken, bytes fundContract, int fundAmount, bytes asset1Contract, bytes asset1Category, int asset1Amount, bytes asset2Contract, bytes asset2Category, int asset2Amount)
{
    // i - inflow manager
    // i + 1 - fund manager
    //
    // o - inflow manager
    // o + 1 - fund manager
    // o + 2 - asset 1
    // o + 3 - asset 2
    function inflow() {
        // check input
        require(tx.inputs[this.activeInputIndex].tokenCategory == inflowToken);
        // spend input back to the contract
        require(tx.inputs[this.activeInputIndex].lockingBytecode == tx.outputs[this.activeInputIndex].lockingBytecode);
        require(tx.inputs[this.activeInputIndex].value == tx.outputs[this.activeInputIndex].value);
        require(tx.inputs[this.activeInputIndex].tokenCategory == tx.outputs[this.activeInputIndex].tokenCategory);


        // fund contract is next in the transaction
        // contract already returns UTXO
        int fundInputIndex = this.activeInputIndex + 1;
        require(tx.inputs[fundInputIndex].lockingBytecode == fundContract);
        
        int fundReleasedAmount = tx.inputs[fundInputIndex].tokenAmount - tx.outputs[fundInputIndex].tokenAmount;
        require(fundReleasedAmount % fundAmount == 0); // ensure a multiple of the fund amount
        fundReleasedAmount = fundReleasedAmount / fundAmount;

        //
        int assetOutputIndex = fundInputIndex + 1;
        require(tx.outputs[assetOutputIndex].lockingBytecode == asset1Contract);
        require(tx.outputs[assetOutputIndex].tokenCategory == asset1Category);
        require(tx.outputs[assetOutputIndex].tokenAmount % asset1Amount == 0); // ensure a multiple of the asset amount
        int asset1CollectedAmount = tx.outputs[assetOutputIndex].tokenAmount / asset1Amount;
        require(asset1CollectedAmount == fundReleasedAmount);

        //
        assetOutputIndex = assetOutputIndex + 1;
        require(tx.outputs[assetOutputIndex].lockingBytecode == asset2Contract);
        require(tx.outputs[assetOutputIndex].tokenCategory == asset2Category);
        require(tx.outputs[assetOutputIndex].tokenAmount % asset2Amount == 0); // ensure a multiple of the asset amount
        int asset2CollectedAmount = tx.outputs[assetOutputIndex].tokenAmount / asset2Amount;
        require(asset2CollectedAmount == fundReleasedAmount);
    }

    function outflow() {
        // check input
        require(tx.inputs[this.activeInputIndex].tokenCategory == outflowToken);
        // spend input back to the contract
        require(tx.inputs[this.activeInputIndex].lockingBytecode == tx.outputs[this.activeInputIndex].lockingBytecode);
        require(tx.inputs[this.activeInputIndex].value == tx.outputs[this.activeInputIndex].value);
        require(tx.inputs[this.activeInputIndex].tokenCategory == tx.outputs[this.activeInputIndex].tokenCategory);

        // fund contract is next in the transaction
        int fundInputIndex = this.activeInputIndex + 1;
        require(tx.inputs[fundInputIndex].lockingBytecode == fundContract);
        
        int fundLockingAmount = tx.outputs[fundInputIndex].tokenAmount - tx.inputs[fundInputIndex].tokenAmount;
        require(fundLockingAmount % fundAmount == 0); // ensure a multiple of the fund amount
        fundLockingAmount = fundLockingAmount / fundAmount;

        int inputIndex = 0;
        int asset1ReleaseAmount = 0;
        int asset2ReleaseAmount = 0;
        do {
            if(tx.inputs[inputIndex].lockingBytecode == asset1Contract && tx.inputs[inputIndex].tokenCategory == asset1Category) {
                asset1ReleaseAmount = asset1ReleaseAmount + tx.inputs[inputIndex].tokenAmount;
            }

            if(tx.inputs[inputIndex].lockingBytecode == asset2Contract && tx.inputs[inputIndex].tokenCategory == asset2Category) {
                asset2ReleaseAmount = asset2ReleaseAmount + tx.inputs[inputIndex].tokenAmount;
            }

            inputIndex = inputIndex + 1;
        } while(inputIndex < tx.inputs.length);

        int outputIndex = 0;
        do {
            if(tx.outputs[outputIndex].lockingBytecode == asset1Contract && tx.outputs[outputIndex].tokenCategory == asset1Category) {
                asset1ReleaseAmount = asset1ReleaseAmount - tx.outputs[outputIndex].tokenAmount;
            }

            if(tx.outputs[outputIndex].lockingBytecode == asset2Contract && tx.outputs[outputIndex].tokenCategory == asset2Category) {
                asset2ReleaseAmount = asset2ReleaseAmount - tx.outputs[outputIndex].tokenAmount;
            }

            outputIndex = outputIndex + 1;
        } while(outputIndex < tx.outputs.length);

        require(asset1ReleaseAmount % asset1Amount == 0); // ensure a multiple of the fund amount
        require(asset1ReleaseAmount / asset1Amount == fundLockingAmount);

        require(asset2ReleaseAmount % asset2Amount == 0); // ensure a multiple of the fund amount
        require(asset2ReleaseAmount / asset2Amount == fundLockingAmount);
    }
}
